     1→using System;
     2→using System.IO.Ports;
     3→using System.Text;
     4→using System.Threading;
     5→using System.Diagnostics;
     6→
     7→namespace NoiseTest
     8→{
     9→    /// <summary>
    10→    /// LS PLC (XGT ASCII) IO 드라이버 안정판 (IN/OUT 64점)
    11→    /// - ReadLoop(수신 스레드) + 누적버퍼 + ETX 프레임 처리
    12→    /// - 상태머신으로 IN 읽기 → OUT 쓰기
    13→    /// - 타임아웃 복구 / 포트 재오픈 / 안전 로깅
    14→    /// - 출력 신뢰성 패치: 락/스냅샷/커밋 + 버전 관리
    15→    /// </summary>
    16→    public sealed class LsPlcIoFast : IDisposable
    17→    {
    18→        // ===== 설정 =====
    19→        public int BaudRate { get; }
    20→        public int PollDelayMs { get; set; } = 10;          // 워커 루프 주기
    21→        public int ResponseTimeoutMs { get; set; } = 1000;  // 응답 타임아웃
    22→        public int ReopenOnTimeoutCount { get; set; } = 3;  // 연속 타임아웃 N회 → 재오픈
    23→        public bool EnableLog { get; set; } = true;
    24→        public bool VerboseTxRx { get; set; } = false;
    25→        public Action<string> Log { get; set; }
    26→
    27→        // 주소
    28→        private const string ADR_IN0 = "%DW4000";
    29→        private const string ADR_IN1 = "%DW4032";
    30→        private const string ADR_OUT0 = "%DW5000";
    31→        private const string ADR_OUT1 = "%DW5032";
    32→        private const string CNT_32 = "20"; // 32 word
    33→
    34→        // 내부 상태
    35→        private readonly SerialPort _port;
    36→        private Thread _rxThread;
    37→        private Thread _workThread;
    38→        private volatile bool _running;
    39→
    40→        private readonly object _rxLock = new object();
    41→        private byte[] _rxAccum = new byte[8192];
    42→        private int _rxAccumLen = 0;
    43→
    44→        private readonly object _txLock = new object();
    45→        private readonly object _outLock = new object(); // 출력 배열 보호 락
    46→
    47→        private readonly bool[] _in = new bool[64];
    48→        private readonly bool[] _out = new bool[64];
    49→        private volatile bool _outDirty = false;
    50→
    51→        // ★ 출력 변경 버전 관리 (출력 유실 방지용)
    52→        private int _outVersion = 0;          // Commit 호출 시 증가하는 버전
    53→        private int _writeCycleVersion = 0;   // 현재 송신 사이클에서 사용 중인 버전
    54→
    55→        private static readonly byte ENQ = 0x05;
    56→        private static readonly byte EOT = 0x04;
    57→        private static readonly byte ETX = 0x03;
    58→
    59→        private readonly Stopwatch _awaitSw = new Stopwatch();
    60→        private int _consecutiveTimeouts = 0;
    61→        private volatile bool _waiting = false;
    62→
    63→        // 상태머신 스텝
    64→        private int _step = 0;
    65→        // 0: R IN0 송신 예정
    66→        // 1: R IN0 응답 대기/파싱
    67→        // 2: R IN1 송신 예정
    68→        // 3: R IN1 응답 대기/파싱
    69→        // 4: (Dirty면) W OUT0 송신 예정, 아니면 6
    70→        // 5: W OUT0 응답 대기
    71→        // 6: (Dirty면) W OUT1 송신 예정, 아니면 0
    72→        // 7: W OUT1 응답 대기
    73→
    74→        public LsPlcIoFast(string portName, int baudrate = 9600)
    75→        {
    76→            BaudRate = baudrate;
    77→
    78→            // 기본 로그 핸들러
    79→            Log = new Action<string>(EmptyLog);
    80→
    81→            _port = new SerialPort(portName, baudrate, Parity.None, 8, StopBits.One);
    82→            _port.Encoding = Encoding.ASCII;
    83→            _port.ReadTimeout = 1000;
    84→            _port.WriteTimeout = 1000;
    85→            _port.NewLine = "\r";
    86→        }
    87→
    88→        // ===== 외부 API =====
    89→        public void Open()
    90→        {
    91→            if (_running)
    92→            {
    93→                return;
    94→            }
    95→
    96→            try
    97→            {
    98→                if (!_port.IsOpen)
    99→                {
   100→                    _port.Open();
   101→                }
   102→
   103→                _running = true;
   104→
   105→                _rxThread = new Thread(ReadLoop);
   106→                _rxThread.IsBackground = true;
   107→                _rxThread.Priority = ThreadPriority.AboveNormal;
   108→
   109→                _workThread = new Thread(WorkLoop);
   110→                _workThread.IsBackground = true;
   111→                _workThread.Priority = ThreadPriority.AboveNormal;
   112→
   113→                _rxThread.Start();
   114→                _workThread.Start();
   115→
   116→                LogInfo("PLC OPEN");
   117→            }
   118→            catch (Exception ex)
   119→            {
   120→                _running = false;
   121→                LogInfo("[ERR] PLC OPEN 실패: " + ex.Message);
   122→            }
   123→        }
   124→
   125→        public void Close()
   126→        {
   127→            if (!_running)
   128→            {
   129→                return;
   130→            }
   131→
   132→            _running = false;
   133→
   134→            try
   135→            {
   136→                if (_workThread != null)
   137→                {
   138→                    _workThread.Join(300);
   139→                }
   140→            }
   141→            catch
   142→            {
   143→            }
   144→
   145→            try
   146→            {
   147→                if (_rxThread != null)
   148→                {
   149→                    _rxThread.Join(300);
   150→                }
   151→            }
   152→            catch
   153→            {
   154→            }
   155→
   156→            if (_port.IsOpen)
   157→            {
   158→                _port.Close();
   159→            }
   160→
   161→            LogInfo("PLC CLOSE");
   162→        }
   163→
   164→        public void Dispose()
   165→        {
   166→            Close();
   167→        }
   168→
   169→        // ===== 출력 제어 =====
   170→        public void Do_On(int bit)
   171→        {
   172→            if ((uint)bit >= 64u)
   173→            {
   174→                return;
   175→            }
   176→
   177→            lock (_outLock)
   178→            {
   179→                if (!_out[bit])
   180→                {
   181→                    _out[bit] = true;
   182→                    _outDirty = true;
   183→                    _outVersion++;
   184→                }
   185→            }
   186→        }
   187→
   188→        public void Do_Off(int bit)
   189→        {
   190→            if ((uint)bit >= 64u)
   191→            {
   192→                return;
   193→            }
   194→
   195→            lock (_outLock)
   196→            {
   197→                if (_out[bit])
   198→                {
   199→                    _out[bit] = false;
   200→                    _outDirty = true;
   201→                    _outVersion++;
   202→                }
   203→            }
   204→        }
   205→
   206→        // 같은 값이어도 재전송이 필요할 때(옵션)
   207→        public void Do_On_Force(int bit)
   208→        {
   209→            if ((uint)bit >= 64u)
   210→            {
   211→                return;
   212→            }
   213→
   214→            lock (_outLock)
   215→            {
   216→                _out[bit] = true;
   217→                _outDirty = true;
   218→                _outVersion++;
   219→            }
   220→        }
   221→
   222→        public void Do_Off_Force(int bit)
   223→        {
   224→            if ((uint)bit >= 64u)
   225→            {
   226→                return;
   227→            }
   228→
   229→            lock (_outLock)
   230→            {
   231→                _out[bit] = false;
   232→                _outDirty = true;
   233→                _outVersion++;
   234→            }
   235→        }
   236→
   237→        // 즉시 쓰기 단계로 진입시키는 트리거
   238→        public void Commit()
   239→        {
   240→            // ★ 버전 증가로 "이 이후 변경이 반영되어야 한다"는 사실을 남긴다.
   241→            lock (_outLock)
   242→            {
   243→                _outDirty = true;
   244→                _outVersion++;
   245→            }
   246→
   247→            if (!_waiting)
   248→            {
   249→                _step = 4; // 다음 루프에서 W OUT0 → W OUT1
   250→            }
   251→        }
   252→
   253→        public void FlushOutputs()
   254→        {
   255→            // 재전송 강제용: Dirty + 버전 증가
   256→            lock (_outLock)
   257→            {
   258→                _outDirty = true;
   259→                _outVersion++;
   260→            }
   261→        }
   262→
   263→        public bool GetOutput(int bit)
   264→        {
   265→            if ((uint)bit >= 64u)
   266→            {
   267→                return false;
   268→            }
   269→
   270→            lock (_outLock)
   271→            {
   272→                return _out[bit];
   273→            }
   274→        }
   275→
   276→        public bool GetInput(int bit)
   277→        {
   278→            if ((uint)bit >= 64u)
   279→            {
   280→                return false;
   281→            }
   282→
   283→            return _in[bit];
   284→        }
   285→
   286→        // ===== 워커 루프 (상태머신) =====
   287→        private void WorkLoop()
   288→        {
   289→            while (_running)
   290→            {
   291→                try
   292→                {
   293→                    // 타임아웃 감시
   294→                    if (_waiting && _awaitSw.IsRunning && _awaitSw.ElapsedMilliseconds > ResponseTimeoutMs)
   295→                    {
   296→                        _consecutiveTimeouts++;
   297→                        LogInfo("[TIMEOUT " + _consecutiveTimeouts + "] step=" + _step + " → reset");
   298→                        SoftReset();
   299→
   300→                        if (_consecutiveTimeouts >= ReopenOnTimeoutCount)
   301→                        {
   302→                            ReopenPort();
   303→                            _consecutiveTimeouts = 0;
   304→                        }
   305→                    }
   306→
   307→                    if (!_waiting)
   308→                    {
   309→                        switch (_step)
   310→                        {
   311→                            case 0:
   312→                                SendRead(ADR_IN0, CNT_32);
   313→                                Await();
   314→                                _step = 1;
   315→                                break;
   316→
   317→                            case 2:
   318→                                SendRead(ADR_IN1, CNT_32);
   319→                                Await();
   320→                                _step = 3;
   321→                                break;
   322→
   323→                            case 4:
   324→                                if (_outDirty)
   325→                                {
   326→                                    // ★ 현재 쓰기 사이클이 반영해야 할 버전 스냅샷
   327→                                    lock (_outLock)
   328→                                    {
   329→                                        _writeCycleVersion = _outVersion;
   330→                                    }
   331→
   332→                                    SendWrite(ADR_OUT0, 0);
   333→                                    Await();
   334→                                    _step = 5;
   335→                                }
   336→                                else
   337→                                {
   338→                                    _step = 6;
   339→                                }
   340→                                break;
   341→
   342→                            case 6:
   343→                                if (_outDirty)
   344→                                {
   345→                                    SendWrite(ADR_OUT1, 32);
   346→                                    Await();
   347→                                    _step = 7;
   348→                                }
   349→                                else
   350→                                {
   351→                                    _step = 0;
   352→                                }
   353→                                break;
   354→                        }
   355→                    }
   356→                }
   357→                catch (Exception ex)
   358→                {
   359→                    LogInfo("[ERR] Work: " + ex.Message);
   360→                    SoftReset();
   361→                }
   362→
   363→                Thread.Sleep(PollDelayMs);
   364→            }
   365→        }
   366→
   367→        // ===== 수신 스레드 =====
   368→        private void ReadLoop()
   369→        {
   370→            var buf = new byte[2048];
   371→
   372→            while (_running)
   373→            {
   374→                try
   375→                {
   376→                    int n = _port.BaseStream.Read(buf, 0, buf.Length); // blocking
   377→
   378→                    if (n > 0)
   379→                    {
   380→                        AppendRx(buf, n);
   381→                        ProcessFrames();
   382→                    }
   383→                }
   384→                catch (TimeoutException)
   385→                {
   386→                    // ignore
   387→                }
   388→                catch (Exception ex)
   389→                {
   390→                    LogInfo("[ERR] Read: " + ex.Message);
   391→                    Thread.Sleep(10);
   392→                }
   393→            }
   394→        }
   395→
   396→        // ===== RX 누적/프레임 처리 =====
   397→        private void AppendRx(byte[] src, int len)
   398→        {
   399→            lock (_rxLock)
   400→            {
   401→                if (_rxAccumLen + len > _rxAccum.Length)
   402→                {
   403→                    var bigger = new byte[Math.Max(_rxAccum.Length * 2, _rxAccumLen + len)];
   404→                    Buffer.BlockCopy(_rxAccum, 0, bigger, 0, _rxAccumLen);
   405→                    _rxAccum = bigger;
   406→                }
   407→
   408→                Buffer.BlockCopy(src, 0, _rxAccum, _rxAccumLen, len);
   409→                _rxAccumLen += len;
   410→            }
   411→        }
   412→
   413→        private void ProcessFrames()
   414→        {
   415→            while (true)
   416→            {
   417→                int etxIndex;
   418→
   419→                lock (_rxLock)
   420→                {
   421→                    etxIndex = IndexOf(_rxAccum, 0, _rxAccumLen, ETX);
   422→                    if (etxIndex < 0)
   423→                    {
   424→                        return;
   425→                    }
   426→                }
   427→
   428→                string frame;
   429→
   430→                lock (_rxLock)
   431→                {
   432→                    frame = Encoding.ASCII.GetString(_rxAccum, 0, etxIndex + 1); // ETX 포함
   433→                    int remain = _rxAccumLen - (etxIndex + 1);
   434→
   435→                    if (remain > 0)
   436→                    {
   437→                        Buffer.BlockCopy(_rxAccum, etxIndex + 1, _rxAccum, 0, remain);
   438→                    }
   439→
   440→                    _rxAccumLen = remain;
   441→                }
   442→
   443→                if (EnableLog && VerboseTxRx)
   444→                {
   445→                    Log("RX " + frame);
   446→                }
   447→
   448→                if (!_waiting)
   449→                {
   450→                    continue; // 예상 응답이 아닐 때는 무시(필요시 큐잉)
   451→                }
   452→
   453→                try
   454→                {
   455→                    switch (_step)
   456→                    {
   457→                        case 1: // IN0 응답
   458→                            if (!TryParseInputs(frame, 0))
   459→                            {
   460→                                LogInfo("[WARN] IN0 parse fail");
   461→                            }
   462→                            _step = 2;
   463→                            break;
   464→
   465→                        case 3: // IN1 응답
   466→                            if (!TryParseInputs(frame, 32))
   467→                            {
   468→                                LogInfo("[WARN] IN1 parse fail");
   469→                            }
   470→                            _step = 4;
   471→                            break;
   472→
   473→                        case 5: // OUT0 ack
   474→                            _step = 6;
   475→                            break;
   476→
   477→                        case 7: // OUT1 ack
   478→                            // ★ 쓰기 사이클 시작 시점의 버전과 현재 버전이 같을 때만 Dirty 클리어
   479→                            lock (_outLock)
   480→                            {
   481→                                if (_writeCycleVersion == _outVersion)
   482→                                {
   483→                                    _outDirty = false;
   484→                                }
   485→                                // 다르면: 사이클 도중에 Commit이 한 번 더 들어왔다는 뜻 → Dirty 유지
   486→                            }
   487→                            _step = 0;
   488→                            break;
   489→                    }
   490→                }
   491→                finally
   492→                {
   493→                    ResetAwait();
   494→                    _consecutiveTimeouts = 0;
   495→                }
   496→            }
   497→        }
   498→
   499→        // ===== 파서 =====
   500→        // 고정 오프셋(11) 시도 → 부족하면 끝쪽에서 128자리(32*4) 숫자 블록 추출
   501→        private bool TryParseInputs(string frame, int dstOffset)
   502→        {
   503→            int ok = 0;
   504→
   505→            // 1) 고정 오프셋(과거 동작과 동일)
   506→            for (int i = 0; i < 32; i++)
   507→            {
   508→                int pos = 11 + i * 4;
   509→                if (pos + 4 > frame.Length)
   510→                {
   511→                    break;
   512→                }
   513→
   514→                int val;
   515→                if (int.TryParse(frame.Substring(pos, 4), out val))
   516→                {
   517→                    _in[dstOffset + i] = (val != 0);
   518→                    ok++;
   519→                }
   520→                else
   521→                {
   522→                    break;
   523→                }
   524→            }
   525→
   526→            if (ok >= 28)
   527→            {
   528→                return true; // 대부분 맞으면 통과
   529→            }
   530→
   531→            // 2) 후방 탐색: 끝에서부터 숫자 연속 구간 중 128자리 이상 찾기
   532→            int tailStart = FindTailDigitRun(frame, 128);
   533→            if (tailStart >= 0)
   534→            {
   535→                int parsed = 0;
   536→                int end = frame.Length;
   537→
   538→                for (int i = 0; i < 32; i++)
   539→                {
   540→                    int s = end - 4 * (32 - i);
   541→                    if (s < tailStart)
   542→                    {
   543→                        break;
   544→                    }
   545→
   546→                    int v;
   547→                    if (int.TryParse(frame.Substring(s, 4), out v))
   548→                    {
   549→                        _in[dstOffset + i] = (v != 0);
   550→                        parsed++;
   551→                    }
   552→                }
   553→
   554→                return parsed == 32;
   555→            }
   556→
   557→            return false;
   558→        }
   559→
   560→        private static int FindTailDigitRun(string s, int minLen)
   561→        {
   562→            int run = 0;
   563→
   564→            for (int i = s.Length - 1; i >= 0; i--)
   565→            {
   566→                if (char.IsDigit(s[i]))
   567→                {
   568→                    run++;
   569→                }
   570→                else
   571→                {
   572→                    if (run >= minLen)
   573→                    {
   574→                        return i + 1;
   575→                    }
   576→
   577→                    run = 0;
   578→                }
   579→            }
   580→
   581→            if (run >= minLen)
   582→            {
   583→                return 0;
   584→            }
   585→
   586→            return -1;
   587→        }
