   261→        private void pictureBoxOutput_Click(object sender, EventArgs e)
   262→        {
   263→            var pic = sender as PictureBox;
   264→            if (pic == null || FrmMain.io == null) return;
   265→
   266→            int index = -1;
   267→            if (pic.Tag is int i) index = i;
   268→            else if (!int.TryParse(pic.Tag + "", out index)) return;
   269→            if (index < 0 || index >= CH) return;
   270→
   271→            bool next = !FrmMain.io.GetOutput(index);
   272→            if (next) { FrmMain.io.Do_On_Force(index);  FrmMain.io.Commit(); }
   273→            else      { FrmMain.io.Do_Off_Force(index); FrmMain.io.Commit(); }
   274→
   275→            ApplyOnOffStyle(pic, next);
   276→        }
